CREATE OR REPLACE FUNCTION fpa_dep_bal_by_dep_type (as_dep_type char , as_memno char) RETURNS bigint AS $body$
DECLARE

ldc_bal bigint;

BEGIN
select	sum(coalesce(sc_dep_m_creditor.deposit_balance,0)) into STRICT ldc_bal
from		sc_dep_m_rule
		,	  sc_dep_m_creditor
where (sc_dep_m_rule.deposit_type_code = sc_dep_m_creditor.deposit_type_code)
and (sc_dep_m_rule.deposit_type_code = as_dep_type)
and (sc_dep_m_creditor.membership_no = as_memno);

return coalesce(ldc_bal,0);


END;
$body$
LANGUAGE PLPGSQL
